        /// <param name="body">The raw request body as a byte array</param>
        /// <param name="signature">The signature from the X-Signature header</param>
        /// <param name="secret">Your webhook secret (found in the Stream Dashboard)</param>
        /// <returns>true if the signature is valid, false otherwise</returns>
        public static bool VerifySignature(byte[] body, string signature, string secret)
        {
            using var hmac = new HMACSHA256(Encoding.UTF8.GetBytes(secret));
            var hash = hmac.ComputeHash(body);
            var expected = Convert.ToHexString(hash).ToLowerInvariant();

#if NET5_0_OR_GREATER
            return CryptographicOperations.FixedTimeEquals(
                Encoding.UTF8.GetBytes(signature),
                Encoding.UTF8.GetBytes(expected)
            );
#else
            // Fallback for older .NET versions - constant time comparison
            if (signature.Length != expected.Length)
                return false;

            uint result = 0;
            for (int i = 0; i < signature.Length; i++)
            {
                result |= (uint)(signature[i] ^ expected[i]);
            }
            return result == 0;
#endif
        }

        /// <summary>
        /// Verify the HMAC-SHA256 signature of a webhook payload.
        /// </summary>
        /// <param name="body">The raw request body as a string</param>
        /// <param name="signature">The signature from the X-Signature header</param>
        /// <param name="secret">Your webhook secret (found in the Stream Dashboard)</param>
        /// <returns>true if the signature is valid, false otherwise</returns>
        public static bool VerifySignature(string body, string signature, string secret)
        {
            return VerifySignature(Encoding.UTF8.GetBytes(body), signature, secret);
        }

        /// <summary>
        /// Decompress the body if it is gzip-prefixed, otherwise return it as-is.
        ///
        /// Detection uses the first two bytes (0x1F 0x8B). This is reliable because
        /// Stream webhook bodies are always JSON, and JSON cannot start with 0x1F.
        /// </summary>
        /// <param name="body">The raw request body, possibly gzip-compressed</param>
        /// <returns>The uncompressed bytes (or <paramref name="body"/> unchanged if no gzip prefix)</returns>
        /// <exception cref="StreamInvalidWebhookException">If the body has the gzip magic prefix but isn't a valid gzip stream</exception>
        public static byte[] GunzipPayload(byte[] body)
        {
            if (body == null || body.Length < 2 || body[0] != GzipMagic[0] || body[1] != GzipMagic[1])
            {
                return body ?? Array.Empty<byte>();
            }
            try
            {
                using var input = new MemoryStream(body);
                using var gz = new GZipStream(input, CompressionMode.Decompress);
                using var output = new MemoryStream();
                gz.CopyTo(output);
                return output.ToArray();
            }
            catch (Exception e) when (e is InvalidDataException || e is IOException)
            {
                throw new StreamInvalidWebhookException($"gzip decompression failed: {e.Message}", e);
            }
        }

        /// <summary>
        /// base64-decode an SQS Message Body, then gunzip if gzip-prefixed.
        ///
        /// Forward-compat: today the backend emits plain JSON to SQS; once compression
        /// is extended to queue transports, bodies will be base64(gzip(json)). This helper
        /// handles both cases via magic-byte detection in <see cref="GunzipPayload(byte[])"/>.
        ///
        /// Note: if the input is plain JSON (not base64), strict base64 decoding will
        /// fail and throw <see cref="StreamInvalidWebhookException"/>. Callers receiving today's
        /// plain-JSON SQS messages should call <see cref="ParseEvent(byte[])"/> directly with
        /// the body bytes.
        /// </summary>
        /// <exception cref="StreamInvalidWebhookException">If base64 decoding fails or gzip decompression fails</exception>
        public static byte[] DecodeSqsPayload(string messageBody)
        {
            if (messageBody == null)
            {
                throw new StreamInvalidWebhookException("messageBody must not be null");
            }
            byte[] decoded;
            try
            {
                decoded = Convert.FromBase64String(messageBody);
            }
            catch (FormatException e)
            {
                throw new StreamInvalidWebhookException($"invalid base64: {e.Message}", e);
            }
            return GunzipPayload(decoded);
        }

        /// <summary>
        /// Extract the <c>Message</c> field from a standard AWS SNS notification envelope,
        /// then base64-decode and gunzip. The envelope shape is:
        /// <c>{"Type":"Notification","Message":"&lt;base64&gt;","MessageId":"...","TopicArn":"...","Timestamp":"..."}</c>
        /// </summary>
        /// <exception cref="StreamInvalidWebhookException">If the envelope is invalid or the Message field is missing/non-string</exception>
        public static byte[] DecodeSnsPayload(string notificationBody)
        {
            if (notificationBody == null)
            {
                throw new StreamInvalidWebhookException("notificationBody must not be null");
            }
            try
            {
                using var doc = JsonDocument.Parse(notificationBody);
                if (doc.RootElement.ValueKind != JsonValueKind.Object)
                {
                    throw new StreamInvalidWebhookException("SNS envelope must be a JSON object");
                }
                if (!doc.RootElement.TryGetProperty("Message", out var msg) || msg.ValueKind != JsonValueKind.String)
                {
                    throw new StreamInvalidWebhookException("SNS envelope missing 'Message' string field");
                }
                return DecodeSqsPayload(msg.GetString());
            }
            catch (JsonException e)
            {
                throw new StreamInvalidWebhookException($"invalid SNS envelope JSON: {e.Message}", e);
            }
        }

        /// <summary>
        /// Parse a webhook payload and return the typed event for known discriminators or
        /// <see cref="UnknownEvent"/> for well-formed-but-unknown ones.
        ///
        /// Distinct from <see cref="ParseWebhookEvent(byte[])"/>: <c>ParseEvent</c> returns
        /// an <c>UnknownEvent</c> on unrecognized discriminators (forward-compat);
        /// <c>ParseWebhookEvent</c> throws.
        /// </summary>
        /// <returns>The typed event (a generated event class) or an <see cref="UnknownEvent"/> instance</returns>
        /// <exception cref="StreamInvalidWebhookException">For invalid JSON, missing/non-string type field, or any deserialization failure on a known type</exception>
        public static object ParseEvent(byte[] payload)
        {
            if (payload == null || payload.Length == 0)
            {
                throw new StreamInvalidWebhookException("payload must not be empty");
            }

            JsonDocument doc;
            try
            {
                doc = JsonDocument.Parse(payload);
            }
            catch (JsonException e)
            {
                throw new StreamInvalidWebhookException($"failed to parse webhook payload: {e.Message}", e);
            }

            using (doc)
            {
                if (doc.RootElement.ValueKind != JsonValueKind.Object)
                {
                    throw new StreamInvalidWebhookException("webhook payload must be a JSON object");
                }
                if (!doc.RootElement.TryGetProperty("type", out var typeNode) || typeNode.ValueKind != JsonValueKind.String)
                {
                    throw new StreamInvalidWebhookException("webhook payload missing 'type' string field");
                }
                var eventType = typeNode.GetString();
                if (string.IsNullOrEmpty(eventType))
                {
                    throw new StreamInvalidWebhookException("webhook payload missing 'type' string field");
                }

                var eventClass = GetEventTypeClass(eventType);
                if (eventClass == null)
                {
                    DateTimeOffset? createdAt = null;
                    if (doc.RootElement.TryGetProperty("created_at", out var createdNode)
                        && createdNode.ValueKind == JsonValueKind.String
                        && DateTimeOffset.TryParse(createdNode.GetString(), out var parsed))
                    {
                        createdAt = parsed;
                    }
                    return new UnknownEvent(eventType, createdAt, doc.RootElement.Clone());
                }

                try
                {
                    return JsonSerializer.Deserialize(payload, eventClass);
                }
                catch (JsonException e)
                {
                    throw new StreamInvalidWebhookException($"failed to deserialize event: {e.Message}", e);
                }
            }
        }

        /// <summary>
        /// HTTP composite: gunzip (if gzip-prefixed) then verify HMAC-SHA256 then parse.
        ///
        /// The signature header is X-Signature. The signature is HMAC-SHA256 of the
        /// <em>uncompressed</em> JSON body, hex-encoded. Magic-byte detection means callers
        /// can pass either the raw HTTP body or already-decompressed bytes; both work.
        /// </summary>
        /// <exception cref="StreamInvalidWebhookException">For signature mismatches as well as parse/decompression failures; distinguish modes via the exception's <see cref="Exception.Message"/> substring.</exception>
        public static object VerifyAndParseWebhook(byte[] body, string signature, string secret)
        {
            var payload = GunzipPayload(body);
            if (!VerifySignature(payload, signature, secret))
            {
                throw new StreamInvalidWebhookException("webhook signature mismatch");
            }
            return ParseEvent(payload);
        }

        /// <summary>
        /// SQS composite: base64-decode then gunzip (if gzip-prefixed) then parse.
        ///
        /// The backend emits no signature attribute on SQS messages today; this helper
        /// therefore performs no signature verification. If a signed variant is added later,
        /// it'll be a separate function rather than retrofitting this signature.
        /// </summary>
        public static object ParseSqs(string messageBody)
        {
            return ParseEvent(DecodeSqsPayload(messageBody));
        }

        /// <summary>
        /// SNS composite: parse SNS envelope then base64-decode then gunzip then parse.
        /// Same no-signature posture as <see cref="ParseSqs(string)"/>.
        /// </summary>
        public static object ParseSns(string notificationBody)
        {
            return ParseEvent(DecodeSnsPayload(notificationBody));
        }
    }
}
